package development

import (
	"testing"

	"github.com/stretchr/testify/require"
)

func TestEnum_ESTIMATOR_SENSOR_FUSION_SOURCE(t *testing.T) {
	t.Run("zero", func(t *testing.T) {
		var e ESTIMATOR_SENSOR_FUSION_SOURCE
		e.UnmarshalText([]byte{})
		e.MarshalText()
		e.String()
	})

	t.Run("first entry", func(t *testing.T) {
		enc, err := ESTIMATOR_SENSOR_FUSION_SOURCE_GPS.MarshalText()
		require.NoError(t, err)

		var dec ESTIMATOR_SENSOR_FUSION_SOURCE
		err = dec.UnmarshalText(enc)
		require.NoError(t, err)

		require.Equal(t, ESTIMATOR_SENSOR_FUSION_SOURCE_GPS, dec)
	})
}
